import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import useAuthStore from '../store/authStore';
import { phieuTamTruAPI, phongAPI } from '../services/api';
import {
  buildCt01FileName,
  buildCt01PreviewData,
  CT01_NOTES,
  downloadBlob,
  formatDateVN,
} from '../utils/phieuTamTruDocument';
import './PhieuTamTru.css';

const normalizeName = value => value.trim().replace(/\s+/g, ' ');
const isValidName = value => {
  const normalized = normalizeName(value);
  return normalized.length >= 2 && normalized.length <= 100 && !/\d/.test(normalized);
};
const isValidPhone = value => value === '' || /^\d{10,11}$/.test(value);
const isValidCitizenId = value => value === '' || /^\d{9,12}$/.test(value);
const isValidEmail = value => value === '' || /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);

const deriveQuanHe = (phong, user) => {
  if (!phong || !user) return '';
  return phong.maChuPhong === user.maNguoiDung ? 'Chį»§ hį»' : 'NgĘ°į»i thuĆŖ';
};

const createInitialForm = user => ({
  maPhong: '',
  coQuanDangKy: '',
  hoTen: user?.hoTenXacThuc || user?.hoTen || '',
  gioiTinh: '',
  soCanCuocCongDan: user?.soCanCuocCongDan || '',
  soDienThoai: user?.soDienThoai || '',
  email: user?.email || '',
  ngaySinh: user?.ngaySinhXacThuc || '',
  tenChuHo: '',
  quanHeVoiChuHo: '',
  soDinhDanhChuHo: '',
  diaChiThuongTru: user?.diaChiThuongTruXacThuc || '',
  noiDungDeNghi: '',
  ngayBatDau: '',
});

const mapPhieuToForm = phieu => ({
  maPhong: phieu?.maPhong ? String(phieu.maPhong) : '',
  coQuanDangKy: phieu?.coQuanDangKy || '',
  hoTen: phieu?.hoTen || '',
  gioiTinh: phieu?.gioiTinh || '',
  soCanCuocCongDan: phieu?.soCanCuocCongDan || '',
  soDienThoai: phieu?.soDienThoai || '',
  email: phieu?.email || '',
  ngaySinh: phieu?.ngaySinh || '',
  tenChuHo: phieu?.tenChuHo || '',
  quanHeVoiChuHo: phieu?.quanHeVoiChuHo || '',
  soDinhDanhChuHo: phieu?.soDinhDanhChuHo || '',
  diaChiThuongTru: phieu?.diaChiThuongTru || '',
  noiDungDeNghi: phieu?.noiDungDeNghi || '',
  ngayBatDau: phieu?.ngayBatDau || '',
});

function FilledLine({ value, multiline = false }) {
  const className = multiline ? 'ct01-fill-block' : 'ct01-fill';
  const emptyClass = value ? '' : 'is-empty';

  return (
    <div className={`${className} ${emptyClass}`.trim()}>
      {value || '\u00A0'}
    </div>
  );
}

function FieldBlock({ label, value, full = false, multiline = false }) {
  return (
    <div className={`ct01-field-block ${full ? 'full' : ''}`.trim()}>
      <div className="ct01-field-label">{label}</div>
      <FilledLine value={value} multiline={multiline} />
    </div>
  );
}

function SignatureBlock({ title, dateText, signerName = '' }) {
  return (
    <div className="ct01-signature-block">
      <div className="ct01-date">{dateText}</div>
      <div className="ct01-signature-title">{title}</div>
      <div className="ct01-signature-note">(KĆ½, ghi rĆµ hį» tĆŖn)</div>
      <div className="ct01-signature-space" />
      <div className="ct01-signature-name">{signerName}</div>
    </div>
  );
}

function CT01Preview({ data }) {
  const preview = buildCt01PreviewData(data);

  return (
    <div className="ct01-sheet">
      <div className="ct01-header">
        <div className="ct01-header-left">
          Mįŗ«u CT01 ban hĆ nh kĆØm theo ThĆ“ng tĘ° sį» 66/2023/TT-BCA ngĆ y 17/11/2023 cį»§a Bį» trĘ°į»ng Bį» CĆ“ng an
        </div>
        <div className="ct01-header-right">
          <div className="ct01-national-title">Cį»NG HĆA XĆ Hį»I CHį»¦ NGHÄØA VIį»T NAM</div>
          <div className="ct01-national-motto">Äį»c lįŗ­p - Tį»± do - Hįŗ”nh phĆŗc</div>
          <div className="ct01-national-line" />
        </div>
      </div>

      <h2 className="ct01-title">Tį» KHAI THAY Äį»I THĆNG TIN CĘÆ TRĆ</h2>

      <div className="ct01-line">
        <strong>KĆ­nh gį»­i(1):</strong>
        <span className="ct01-inline-fill">{preview.coQuanDangKy || '\u00A0'}</span>
      </div>

      <div className="ct01-grid">
        <FieldBlock label="1. Hį», chį»Æ Äį»m vĆ  tĆŖn" value={preview.hoTen} />
        <FieldBlock label="2. NgĆ y, thĆ”ng, nÄm sinh" value={preview.ngaySinhText} />
